100	/// Safety classification for the restriction wrapper's `// safety formula`
101	/// line: a formula is safety iff its negation-normal form contains NO
102	/// existential quantifier — msg-sort or temporal alike (probes q_s1/q_s2:
103	/// ∃ in positive polarity anywhere, including a `¬∃` antecedent that
104	/// double-negates back, defeats it; `¬∃` in conclusion and top-level `¬∃`
105	/// remain safety).
106	pub(crate) fn is_safety(f: &Formula) -> bool {
107	    !has_existential_in_nnf(f, false)
108	}
