    if preds.is_empty() {
        return None;
    }
    // Batch echo (fixed width 110/73): route the whole predicate run
    // through the vendored clean crate (`predicate: <fact><=><formula>`
    // per predicate, blank-line separated — the margin-0 body splice).
    // A predicate's formal args are always plain sorted variables and
    // the head carries no persistence/annotations, so extract the params
    // and hand the (arity-1 folded, sort-resolved) body to the clean
    // renderer; every solver transform stays PORTED here.  The
    // interactive web source view (narrower display width) keeps the
    // ported per-predicate join below — see `batch_echo_width` — as does
    // any (corpus-absent) predicate whose head is not a plain
    // var-parametrised fact.
    let clean_items: Option<Vec<(String, Vec<p::VarSpec>, p::Formula)>> =
        if batch_echo_width() {
            preds.iter().map(|pr| {
                if pr.fact.persistent || !pr.fact.annotations.is_empty() {
                    return None;
                }
                let params: Option<Vec<p::VarSpec>> = pr.fact.args.iter()
                    .map(|a| match a {
                        p::Term::Var(v) => Some(v.clone()),
                        _ => None,
                    })
                    .collect();
                let body = pf::resolve_formula_sorts(
                    &crate::elaborate::rewrite_arity1_formula(&pr.formula, arity1));
                Some((pr.fact.name.clone(), params?, body))
            }).collect()
        } else {
            None
        };
    if let Some(items) = clean_items {
        return Some(crate::pretty_clean_adapt::predicates_section(&items));
    }
    let lines: Vec<String> = preds.iter()
        .map(|pr| render_predicate(pr, arity1))
        .collect();
    Some(lines.join("\n\n"))
}

